class Solution {
public:
    vector<int> separateDigits(vector<int>& nums) {
        vector<int> result;
        for (int num : nums) {
            string str = to_string(num);
            for (char c : str) {
                result.push_back(c - '0');
            }
        }
        return result;
    }
};
